///|
fn[T : @facade.Service] generic_service_id(value : T) -> Int {
  @facade.Service::service_id(value)
}

///|
test "grader consumes the complete facade surface" {
  let handle : @facade.Handle = @facade.open_handle(42)
  assert_eq(generic_service_id(handle), 42)
}

