///|
test "grader preserves type and trait identity" {
  let from_facade : @origin.Handle = @facade.open_handle(11)
  let from_origin : @facade.Handle = @origin.open_handle(12)
  let facade_service : &@facade.Service = from_facade
  let origin_service : &@origin.Service = facade_service
  assert_eq(@origin.Service::service_id(origin_service), 11)
  assert_eq(@facade.Service::service_id(from_origin), 12)
}
